fixtures.vulnerable:
import { createWalletClient, http, type Account, type Hex } from "viem";

export async function submitTransfer(
  client: ReturnType<typeof createWalletClient>,
  account: Account,
  to: Hex,
  value: bigint,
): Promise<Hex> {
  // VULNERABLE: fire-and-forget. sendTransaction resolves to a HASH the instant
  // the tx is broadcast — not a mined receipt. We hand it back as if it settled.
  const hash = await client.sendTransaction({ account, to, value });
  return hash;
}

fixtures.fixed:
import { createWalletClient, createPublicClient, http, type Account, type Hex } from "viem";

export async function submitTransfer(
  client: ReturnType<typeof createWalletClient>,
  publicClient: ReturnType<typeof createPublicClient>,
  account: Account,
  to: Hex,
  value: bigint,
) {
  // FIXED: block until the transaction is mined, then act on the receipt.
  const hash = await client.sendTransaction({ account, to, value });
  const receipt = await publicClient.waitForTransactionReceipt({ hash });
  return receipt;
}
